// redisBigHashHex and valkeyBigHashHex are live DUMP blobs of a 200-field hash (field1..field200 =>
// value1..value200) from Redis 8.8 and Valkey 9.1. Both are the LZF-compressed listpack form (type
// 16), identical except for the RDB version and checksum in the footer, so they exercise the LZF
// decoder and the listpack forward walk on a real large-hash payload.
const redisBigHashHex = ""
const valkeyBigHashHex = ""

// redisBigSetHex and valkeyBigSetHex are live DUMP blobs of a 200-member string set (member1..
// member200) from Redis 8.8 and Valkey 9.1. Both are the plain hashtable form (RDB_TYPE_SET, type 2):
// a member count then that many member strings in the servers' own iteration order, which differs
// between them and from insertion order, so the decoder must not assume any ordering.
const redisBigSetHex = ""
const valkeyBigSetHex = ""

// redisBigZsetHex and valkeyBigZsetHex are live DUMP blobs of a 200-member sorted set (member1..
// member200 scored 1..200) from Redis 8.8 and Valkey 9.1. Both are the skiplist form (RDB_TYPE_ZSET_2,
// type 5): a member count then that many member/score pairs, each score an 8-byte little-endian binary
// double, emitted in descending score order. This exercises the binary-double zset decoder on a real
// large payload across the two RDB versions and checksums.
const redisBigZsetHex = ""
const valkeyBigZsetHex = ""

// redisSmallListHex and valkeySmallListHex are live DUMP blobs of the 5-element list [alpha,
// beta, 12345, -7, gamma] from Redis 8.8 and Valkey 9.1. Both are the quicklist form (type 18)
// with a single PACKED node holding a listpack, the shape both servers emit for a small list, so
// they exercise the PACKED-node path and the listpack forward walk on a real payload.
const redisSmallListHex = "1201022222000000050085616c70686106846265746105f1393003dff9028567616d6d6106ff0e00f7bf0996bfb12cda"
const valkeySmallListHex = "1201022222000000050085616c70686106846265746105f1393003dff9028567616d6d6106ff50004ace187872d05f5f"

// redisBigListHex and valkeyBigListHex are live DUMP blobs of a 500-element list (item1..item500)
// from Redis 8.8 and Valkey 9.1. Both are the quicklist form (type 18) with the node listpack
// LZF-compressed, so they drive the PACKED-node path through the LZF decoder on a blob big enough
// to span the listpack integer and string encodings across the two RDB versions and checksums.
const redisBigListHex = ""
const valkeyBigListHex = ""

// hexBlob turns a hex string captured from a live server into the raw bytes RESTORE takes. The
// cross-engine cases embed blobs produced by Redis 8.8 and Valkey 9.1 so the decoder is exercised
// against real footers (RDB version 14 and 80) and the LZF form Redis writes for a long value.
func hexBlob(t *testing.T, s string) string {
	t.Helper()
	b, err := hex.DecodeString(s)
	if err != nil {
		t.Fatalf("bad hex %q: %v", s, err)
	}
	return string(b)
}

// TestDumpRestoreRoundTrip proves aki restores exactly what aki dumped, across the string shapes
// that take different RDB encodings: a short raw string, a canonical integer (int-encoded), the
// empty string, a value with embedded NUL and high bytes, and a long value.
func TestDumpRestoreRoundTrip(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	longVal := ""
	for i := 0; i < 400; i++ {
		longVal += "x"
	}
	cases := []string{"hello", "12345", "-42", "007", "", "a\x00b\xffc", longVal}
	for _, val := range cases {
		cmd(t, rw, "SET", "src", val)
		expect(t, rw, "+OK")

		cmd(t, rw, "DUMP", "src")
		reply := readReply(t, rw)
		if len(reply) < 1 || reply[0] != '$' {
			t.Fatalf("DUMP %q reply = %q, want a bulk", val, reply)
		}
		blob := reply[1:]

		// Restore under a fresh name and confirm the value survives the round trip.
		cmd(t, rw, "DEL", "dst")
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", "dst", "0", blob)
		expect(t, rw, "+OK")
		cmd(t, rw, "GET", "dst")
		expect(t, rw, "$"+val)
	}
}

// TestRestoreCrossEngine restores blobs produced by live Redis 8.8 and Valkey 9.1. The two servers
// stamp different RDB versions (14 and 80) and therefore different checksums, so this is the real
// interop test: aki must accept both, including the LZF-compressed long value Redis and Valkey emit.
func TestRestoreCrossEngine(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	long := ""
	for i := 0; i < 400; i++ {
		long += "ab"[i%2 : i%2+1]
	}
	cases := []struct {
		name string
		hex  string
		want string
	}{
		{"redis-hello", "000568656c6c6f0e00112907093607347b", "hello"},
		{"valkey-hello", "000568656c6c6f5000ac5816e7fb6647fe", "hello"},
		{"redis-int", "00c139300e00efcf3258c0cf1cc8", "12345"},
		{"valkey-int", "00c13930500052be23b60dae6f4d", "12345"},
		{"redis-lzf", "00c30d419002616261e0ff01e07a010161620e004d58b9eb60ee99eb", long},
		{"valkey-lzf", "00c30d419002616261e0ff01e07a010161625000f029a805ad8fea6e", long},
	}
	for _, tc := range cases {
		cmd(t, rw, "DEL", tc.name)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", tc.name, "0", hexBlob(t, tc.hex))
		expect(t, rw, "+OK")
		cmd(t, rw, "GET", tc.name)
		expect(t, rw, "$"+tc.want)
	}
}

// TestRestoreErrors matches the argument, checksum, and existence errors both servers give, and
// proves REPLACE overwrites a destination of a different type (a hash) with the restored string.
func TestRestoreErrors(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	good := hexBlob(t, "000568656c6c6f0e00112907093607347b") // Redis DUMP of "hello"

	cmd(t, rw, "RESTORE", "k")
	expect(t, rw, "-ERR wrong number of arguments for 'restore' command")
	cmd(t, rw, "RESTORE", "k", "notint", good)
	expect(t, rw, "-ERR value is not an integer or out of range")
	cmd(t, rw, "RESTORE", "k", "-1", good)
	expect(t, rw, "-ERR Invalid TTL value, must be >= 0")
	cmd(t, rw, "RESTORE", "k", "0", "garbage")
	expect(t, rw, "-ERR DUMP payload version or checksum are wrong")

	// A one-bit flip in the checksum is rejected.
	bad := []byte(good)
	bad[len(bad)-1] ^= 0x01
	cmd(t, rw, "RESTORE", "k", "0", string(bad))
	expect(t, rw, "-ERR DUMP payload version or checksum are wrong")

	// First restore succeeds; a second without REPLACE is a BUSYKEY, with REPLACE it overwrites.
	cmd(t, rw, "RESTORE", "k", "0", good)
	expect(t, rw, "+OK")
	cmd(t, rw, "RESTORE", "k", "0", good)
	expect(t, rw, "-BUSYKEY Target key name already exists.")
	cmd(t, rw, "RESTORE", "k", "0", good, "REPLACE")
	expect(t, rw, "+OK")

	// REPLACE onto a hash drops the whole collection and lands the string.
	cmd(t, rw, "HSET", "h", "f", "v")
	expect(t, rw, ":1")
	cmd(t, rw, "RESTORE", "h", "0", good, "REPLACE")
	expect(t, rw, "+OK")
	cmd(t, rw, "GET", "h")
	expect(t, rw, "$hello")

	// Option validation.
	cmd(t, rw, "RESTORE", "opt", "0", good, "FROB")
	expect(t, rw, "-ERR syntax error")
	cmd(t, rw, "RESTORE", "opt", "0", good, "FREQ", "999")
	expect(t, rw, "-ERR Invalid frequency value, must be >= 0 and <= 255")
	cmd(t, rw, "RESTORE", "opt", "0", good, "IDLETIME")
	expect(t, rw, "-ERR syntax error")
	// IDLETIME and FREQ are accepted with a valid value.
	cmd(t, rw, "RESTORE", "opt", "0", good, "IDLETIME", "10", "FREQ", "5")
	expect(t, rw, "+OK")
}

// TestRestoreTTL sets a relative and an absolute expiry through RESTORE and confirms the key carries
// a positive remaining TTL.
func TestRestoreTTL(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	good := hexBlob(t, "000568656c6c6f0e00112907093607347b")

	cmd(t, rw, "RESTORE", "rel", "100000", good)
	expect(t, rw, "+OK")
	cmd(t, rw, "PTTL", "rel")
	if r := readReply(t, rw); r[0] != ':' || r == ":-1" || r == ":-2" {
		t.Fatalf("PTTL rel = %q, want a positive ttl", r)
	}

	// A far-future absolute timestamp in milliseconds.
	cmd(t, rw, "RESTORE", "abs", "99999999999999", good, "ABSTTL")
	expect(t, rw, "+OK")
	cmd(t, rw, "PTTL", "abs")
	if r := readReply(t, rw); r[0] != ':' || r == ":-1" || r == ":-2" {
		t.Fatalf("PTTL abs = %q, want a positive ttl", r)
	}
}

// TestDumpMissingAndArgs covers DUMP's null reply for a missing key and its arity error. Every
// value type (string, hash, set, zset, list, stream) now has its own slice and round-trips through
// its own test, so DUMP no longer refuses any live key.
func TestDumpMissingAndArgs(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	cmd(t, rw, "DUMP", "nope")
	expect(t, rw, "$-1")
	cmd(t, rw, "DUMP")
	expect(t, rw, "-ERR wrong number of arguments for 'dump' command")
}

// TestDumpRestoreSetRoundTrip dumps a set and restores it under a fresh name, checking every member
// survives. The members mix strings and canonical integers so both the raw and int-encoded RDB
// string forms inside the set body get exercised.
func TestDumpRestoreSetRoundTrip(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	members := []string{"alpha", "beta", "12345", "-7", "gamma"}
	args := append([]string{"SADD", "src"}, members...)
	cmd(t, rw, args...)
	expect(t, rw, ":5")

	cmd(t, rw, "DUMP", "src")
	reply := readReply(t, rw)
	if len(reply) < 1 || reply[0] != '$' {
		t.Fatalf("DUMP set reply = %q, want a bulk", reply)
	}
	blob := reply[1:]

	cmd(t, rw, "DEL", "dst")
	drainReply(t, rw)
	cmd(t, rw, "RESTORE", "dst", "0", blob)
	expect(t, rw, "+OK")
	cmd(t, rw, "SCARD", "dst")
	expect(t, rw, ":5")
	for _, m := range members {
		cmd(t, rw, "SISMEMBER", "dst", m)
		expect(t, rw, ":1")
	}
}

// TestRestoreSetCrossEngine restores set blobs produced by live Redis 8.8 and Valkey 9.1 in all
// three encodings both servers write: a listpack for a small string set, an intset for a small
// all-integer set, and the plain hashtable form for a large set. This proves aki decodes each.
func TestRestoreSetCrossEngine(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	// Listpack string set {alpha, beta, gamma} and intset {1,2,3,100}, from each server.
	cases := []struct {
		name    string
		hex     string
		members []string
	}{
		{"redis-lp", "141b1b000000030085616c706861068462657461058567616d6d6106ff0e00235ea9f7ca1832d1", []string{"alpha", "beta", "gamma"}},
		{"valkey-lp", "141b1b000000030085616c706861068462657461058567616d6d6106ff50009e2fb81907794154", []string{"alpha", "beta", "gamma"}},
		{"redis-is", "0b10020000000400000001000200030064000e0088dd436819fc4838", []string{"1", "2", "3", "100"}},
		{"valkey-is", "0b1002000000040000000100020003006400500035ac5286d49d3bbd", []string{"1", "2", "3", "100"}},
	}
	for _, tc := range cases {
		cmd(t, rw, "DEL", tc.name)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", tc.name, "0", hexBlob(t, tc.hex))
		expect(t, rw, "+OK")
		cmd(t, rw, "SCARD", tc.name)
		expect(t, rw, ":"+strconv.Itoa(len(tc.members)))
		for _, m := range tc.members {
			cmd(t, rw, "SISMEMBER", tc.name, m)
			expect(t, rw, ":1")
		}
	}

	// Large 200-member string set, which both servers emit as the plain hashtable form (type 2).
	big := []string{hexBlob(t, redisBigSetHex), hexBlob(t, valkeyBigSetHex)}
	for i, blob := range big {
		key := "bigset" + string(rune('0'+i))
		cmd(t, rw, "DEL", key)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", key, "0", blob)
		expect(t, rw, "+OK")
		cmd(t, rw, "SCARD", key)
		expect(t, rw, ":200")
		cmd(t, rw, "SISMEMBER", key, "member1")
		expect(t, rw, ":1")
		cmd(t, rw, "SISMEMBER", key, "member200")
		expect(t, rw, ":1")
	}
}

// TestDumpRestoreHashRoundTrip dumps a hash and restores it under a fresh name, then reads every
// field back. The fields cover a plain string value, an integer value that int-encodes, the empty
// value, and a value with an embedded NUL and a high byte, so the RDB string forms inside the hash
// body all get exercised.
func TestDumpRestoreHashRoundTrip(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	fields := [][2]string{{"f1", "v1"}, {"n", "12345"}, {"empty", ""}, {"raw", "a\x00b\xffc"}}
	args := []string{"HSET", "src"}
	for _, fv := range fields {
		args = append(args, fv[0], fv[1])
	}
	cmd(t, rw, args...)
	expect(t, rw, ":4")

	cmd(t, rw, "DUMP", "src")
	reply := readReply(t, rw)
	if len(reply) < 1 || reply[0] != '$' {
		t.Fatalf("DUMP hash reply = %q, want a bulk", reply)
	}
	blob := reply[1:]

	cmd(t, rw, "DEL", "dst")
	drainReply(t, rw)
	cmd(t, rw, "RESTORE", "dst", "0", blob)
	expect(t, rw, "+OK")
	cmd(t, rw, "HLEN", "dst")
	expect(t, rw, ":4")
	for _, fv := range fields {
		cmd(t, rw, "HGET", "dst", fv[0])
		expect(t, rw, "$"+fv[1])
	}
}

// TestRestoreHashCrossEngine restores hash blobs produced by live Redis 8.8 and Valkey 9.1. Both
// servers write the listpack encoding (type 16) for a hash, small ones inline and large ones
// LZF-compressed, so this proves aki decodes the listpack form and the LZF wrapper both emit, across
// the two RDB versions and checksums.
func TestRestoreHashCrossEngine(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	// Small hash {f1:v1, f2:v2} as an inline listpack, from each server.
	small := map[string][2]string{
		"redis-small":  {"101717000000040082663103827631038266320382763203ff0e0071a3947346e7b6cd", ""},
		"valkey-small": {"101717000000040082663103827631038266320382763203ff5000ccd2859d8b86c548", ""},
	}
	for name, tc := range small {
		cmd(t, rw, "DEL", name)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", name, "0", hexBlob(t, tc[0]))
		expect(t, rw, "+OK")
		cmd(t, rw, "HLEN", name)
		expect(t, rw, ":2")
		cmd(t, rw, "HGET", name, "f1")
		expect(t, rw, "$v1")
		cmd(t, rw, "HGET", name, "f2")
		expect(t, rw, "$v2")
	}

	// Large hash of 200 fields field1..field200 => value1..value200, which both servers emit as an
	// LZF-compressed listpack (type 16, LZF string). This drives the LZF decoder and the listpack
	// forward walk over a blob big enough to span every string encoding the packer chose.
	big := []string{
		hexBlob(t, redisBigHashHex),
		hexBlob(t, valkeyBigHashHex),
	}
	for i, blob := range big {
		key := "big" + string(rune('0'+i))
		cmd(t, rw, "DEL", key)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", key, "0", blob)
		expect(t, rw, "+OK")
		cmd(t, rw, "HLEN", key)
		expect(t, rw, ":200")
		cmd(t, rw, "HGET", key, "field1")
		expect(t, rw, "$value1")
		cmd(t, rw, "HGET", key, "field200")
		expect(t, rw, "$value200")
	}
}

// TestDumpRestoreZsetRoundTrip dumps a sorted set and restores it under a fresh name, then reads
// every score back. The members carry an integer score, a fractional score, a negative score, and
// the two infinities, so the binary-double score bytes aki writes and reads round-trip for each of
// the score shapes ZADD accepts, including the ones that print specially.
func TestDumpRestoreZsetRoundTrip(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	pairs := [][2]string{{"7", "a"}, {"2.5", "b"}, {"-3", "c"}, {"inf", "d"}, {"-inf", "e"}}
	args := []string{"ZADD", "src"}
	for _, ps := range pairs {
		args = append(args, ps[0], ps[1])
	}
	cmd(t, rw, args...)
	expect(t, rw, ":5")

	cmd(t, rw, "DUMP", "src")
	reply := readReply(t, rw)
	if len(reply) < 1 || reply[0] != '$' {
		t.Fatalf("DUMP zset reply = %q, want a bulk", reply)
	}
	blob := reply[1:]

	cmd(t, rw, "DEL", "dst")
	drainReply(t, rw)
	cmd(t, rw, "RESTORE", "dst", "0", blob)
	expect(t, rw, "+OK")
	cmd(t, rw, "ZCARD", "dst")
	expect(t, rw, ":5")
	for _, ps := range pairs {
		cmd(t, rw, "ZSCORE", "dst", ps[1])
		expect(t, rw, "$"+ps[0])
	}
}

// TestRestoreZsetCrossEngine restores sorted-set blobs produced by live Redis 8.8 and Valkey 9.1 in
// both encodings the servers write: a listpack for a small set, where the scores ride inline as
// listpack entries, and the skiplist form (ZSET_2, type 5) for a large set, where each score is an
// 8-byte little-endian binary double. This proves aki decodes both zset encodings each server emits.
func TestRestoreZsetCrossEngine(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	// Small zset {a:1, b:2.5, c:-3} as a listpack (type 17), from each server.
	cases := []struct {
		name  string
		hex   string
		pairs [][2]string
	}{
		{"redis-lp", "111a1a0000000600816302dffd02816102010181620283322e3504ff0e00d4d1c2cefac1c8b3", [][2]string{{"a", "1"}, {"b", "2.5"}, {"c", "-3"}}},
		{"valkey-lp", "111a1a0000000600816302dffd02816102010181620283322e3504ff500069a0d32037a0bb36", [][2]string{{"a", "1"}, {"b", "2.5"}, {"c", "-3"}}},
	}
	for _, tc := range cases {
		cmd(t, rw, "DEL", tc.name)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", tc.name, "0", hexBlob(t, tc.hex))
		expect(t, rw, "+OK")
		cmd(t, rw, "ZCARD", tc.name)
		expect(t, rw, ":"+strconv.Itoa(len(tc.pairs)))
		for _, ps := range tc.pairs {
			cmd(t, rw, "ZSCORE", tc.name, ps[0])
			expect(t, rw, "$"+ps[1])
		}
	}

	// Large 200-member zset member1..member200 scored 1..200, which both servers emit as the skiplist
	// form (ZSET_2, type 5) with binary-double scores.
	big := []string{hexBlob(t, redisBigZsetHex), hexBlob(t, valkeyBigZsetHex)}
	for i, blob := range big {
		key := "bigzset" + string(rune('0'+i))
		cmd(t, rw, "DEL", key)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", key, "0", blob)
		expect(t, rw, "+OK")
		cmd(t, rw, "ZCARD", key)
		expect(t, rw, ":200")
		cmd(t, rw, "ZSCORE", key, "member1")
		expect(t, rw, "$1")
		cmd(t, rw, "ZSCORE", key, "member200")
		expect(t, rw, "$200")
	}
}

// TestDumpRestoreListRoundTrip dumps a list and restores it under a fresh name, then reads every
// position back in order. The elements mix strings and canonical integers, including a negative, so
// both the raw and int-encoded RDB string forms inside the quicklist nodes get exercised, and the
// order-preserving position window survives the round trip head to tail.
func TestDumpRestoreListRoundTrip(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	elems := []string{"alpha", "beta", "12345", "-7", "gamma", ""}
	args := append([]string{"RPUSH", "src"}, elems...)
	cmd(t, rw, args...)
	expect(t, rw, ":"+strconv.Itoa(len(elems)))

	cmd(t, rw, "DUMP", "src")
	reply := readReply(t, rw)
	if len(reply) < 1 || reply[0] != '$' {
		t.Fatalf("DUMP list reply = %q, want a bulk", reply)
	}
	blob := reply[1:]

	cmd(t, rw, "DEL", "dst")
	drainReply(t, rw)
	cmd(t, rw, "RESTORE", "dst", "0", blob)
	expect(t, rw, "+OK")
	cmd(t, rw, "LLEN", "dst")
	expect(t, rw, ":"+strconv.Itoa(len(elems)))
	for i, e := range elems {
		cmd(t, rw, "LINDEX", "dst", strconv.Itoa(i))
		expect(t, rw, "$"+e)
	}
}

// TestRestoreListCrossEngine restores list blobs produced by live Redis 8.8 and Valkey 9.1. Both
// servers serialize every list as the quicklist form (type 18): a small list as a single PACKED
// listpack node, a large one as PACKED nodes with the listpack LZF-compressed. This proves aki
// decodes the PACKED-node path and the LZF wrapper both emit, across the two RDB versions and
// checksums, and flattens the nodes back into the right head-to-tail order.
func TestRestoreListCrossEngine(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	// Small list [alpha, beta, 12345, -7, gamma] as a single PACKED node, from each server.
	small := []struct {
		name  string
		hex   string
		elems []string
	}{
		{"redis-lp", redisSmallListHex, []string{"alpha", "beta", "12345", "-7", "gamma"}},
		{"valkey-lp", valkeySmallListHex, []string{"alpha", "beta", "12345", "-7", "gamma"}},
	}
	for _, tc := range small {
		cmd(t, rw, "DEL", tc.name)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", tc.name, "0", hexBlob(t, tc.hex))
		expect(t, rw, "+OK")
		cmd(t, rw, "LLEN", tc.name)
		expect(t, rw, ":"+strconv.Itoa(len(tc.elems)))
		for i, e := range tc.elems {
			cmd(t, rw, "LINDEX", tc.name, strconv.Itoa(i))
			expect(t, rw, "$"+e)
		}
	}

	// Large 500-element list item1..item500, which both servers emit as an LZF-compressed quicklist.
	big := []string{hexBlob(t, redisBigListHex), hexBlob(t, valkeyBigListHex)}
	for i, blob := range big {
		key := "biglist" + string(rune('0'+i))
		cmd(t, rw, "DEL", key)
		drainReply(t, rw)
		cmd(t, rw, "RESTORE", key, "0", blob)
		expect(t, rw, "+OK")
		cmd(t, rw, "LLEN", key)
		expect(t, rw, ":500")
		cmd(t, rw, "LINDEX", key, "0")
		expect(t, rw, "$item1")
		cmd(t, rw, "LINDEX", key, "499")
		expect(t, rw, "$item500")
		cmd(t, rw, "LINDEX", key, "-1")
		expect(t, rw, "$item500")
	}
}

// TestDumpRestoreStreamRoundTrip dumps a stream and restores it under a fresh name, then checks the
// entries, the consumer group, and its pending list all survive. The entries carry explicit IDs so
// the master-ID delta and listpack item encoding round-trip exactly, and the group is left with a
// consumer holding both entries pending so the global PEL, the consumer record, and the per-entry
// delivery metadata all pass through the type-21 body.
func TestDumpRestoreStreamRoundTrip(t *testing.T) {
	rw, cleanup := dialTestServer(t)
	defer cleanup()

	cmd(t, rw, "XADD", "src", "1-1", "f", "v")
	expect(t, rw, "$1-1")
	cmd(t, rw, "XADD", "src", "2-2", "a", "b", "c", "d")
	expect(t, rw, "$2-2")
	cmd(t, rw, "XGROUP", "CREATE", "src", "g1", "0")
	expect(t, rw, "+OK")
	cmd(t, rw, "XREADGROUP", "GROUP", "g1", "c1", "COUNT", "10", "STREAMS", "src", ">")
	drainReply(t, rw)

	cmd(t, rw, "DUMP", "src")
	reply := readReply(t, rw)
	if len(reply) < 1 || reply[0] != '$' {
		t.Fatalf("DUMP stream reply = %q, want a bulk", reply)
	}
	blob := reply[1:]

	cmd(t, rw, "DEL", "dst")
	drainReply(t, rw)
	cmd(t, rw, "RESTORE", "dst", "0", blob)
	expect(t, rw, "+OK")

	cmd(t, rw, "XLEN", "dst")
	expect(t, rw, ":2")
	cmd(t, rw, "XRANGE", "dst", "-", "+")
	if got := readReplyDeep(t, rw); got != "[[1-1 [f v]] [2-2 [a b c d]]]" {
		t.Fatalf("XRANGE dst = %q", got)
	}

	// The group and its consumer survive, with both entries still pending under c1.
	cmd(t, rw, "XINFO", "GROUPS", "dst")
	if got := readReplyDeep(t, rw); !strings.Contains(got, "g1") || !strings.Contains(got, "pending 2") {
		t.Fatalf("XINFO GROUPS dst = %q, want g1 with pending 2", got)
	}
	cmd(t, rw, "XPENDING", "dst", "g1")
	if got := readReplyDeep(t, rw); got != "[2 1-1 2-2 [[c1 2]]]" {
		t.Fatalf("XPENDING dst = %q", got)
	}
}
